const raw = $input.first().json.data || '';
function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'hourly');
const expectedFreshnessHours = 3;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const sensor = 'VIIRS_SNPP_NRT';
const lookbackDays = 5;
const bbox = '-75,-35,-33,6';
const sourceUrlTemplate = `https://firms.modaps.eosdis.nasa.gov/api/area/csv/[NASA_FIRMS_KEY]/${sensor}/${bbox}/${lookbackDays}`;

function parseCsvLine(line) {
  const values = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      values.push(current);
      current = '';
    } else {
      current += char;
    }
  }

  values.push(current);
  return values;
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

function buildDetectionUtc(acqDate, acqTime) {
  if (!acqDate) return null;
  const time = String(acqTime || '').padStart(4, '0');
  const hh = time.slice(0, 2);
  const mm = time.slice(2, 4);
  return `${acqDate}T${hh}:${mm}:00Z`;
}

function percentile(sortedValues, p) {
  if (!sortedValues.length) return null;
  const index = Math.min(sortedValues.length - 1, Math.max(0, Math.ceil(sortedValues.length * p) - 1));
  return Number(sortedValues[index].toFixed(2));
}

const lines = raw.split(/\r?\n/).filter((line) => line.trim() !== '');
if (!lines.length) {
  throw new Error('NASA FIRMS response is empty');
}

const headers = parseCsvLine(lines[0]).map((header) => header.trim());
const requiredHeaders = ['latitude', 'longitude', 'acq_date', 'acq_time', 'frp'];
for (const header of requiredHeaders) {
  if (!headers.includes(header)) {
    throw new Error(`Unexpected NASA FIRMS CSV schema: missing ${header}`);
  }
}

const numericFields = new Set(['latitude', 'longitude', 'bright_ti4', 'bright_ti5', 'scan', 'track', 'frp']);

const detections = lines.slice(1).map((line) => {
  const values = parseCsvLine(line);
  const row = {};

  headers.forEach((header, index) => {
    const rawValue = (values[index] ?? '').trim();
    row[header] = numericFields.has(header) ? toNumber(rawValue) : rawValue;
  });

  row.acq_time = String(row.acq_time || '').padStart(4, '0');
  row.detection_utc = buildDetectionUtc(row.acq_date, row.acq_time);

  return row;
}).filter((row) => row.latitude !== null && row.longitude !== null && row.acq_date);

const totalDetections = detections.length;
const detectionsByDay = {};
const confidenceCounts = {};
const daynightCounts = {};
const satelliteCounts = {};

for (const detection of detections) {
  const acqDate = detection.acq_date || 'unknown';
  const confidence = String(detection.confidence || 'unknown');
  const daynight = String(detection.daynight || 'unknown');
  const satellite = String(detection.satellite || 'unknown');

  detectionsByDay[acqDate] = (detectionsByDay[acqDate] || 0) + 1;
  confidenceCounts[confidence] = (confidenceCounts[confidence] || 0) + 1;
  daynightCounts[daynight] = (daynightCounts[daynight] || 0) + 1;
  satelliteCounts[satellite] = (satelliteCounts[satellite] || 0) + 1;
}

const frpValues = detections.map((detection) => detection.frp).filter((value) => typeof value === 'number');
const sortedFrpValues = [...frpValues].sort((a, b) => a - b);
const frpSum = frpValues.reduce((sum, value) => sum + value, 0);
const maxFrp = sortedFrpValues.length ? Number(sortedFrpValues[sortedFrpValues.length - 1].toFixed(2)) : null;
const minFrp = sortedFrpValues.length ? Number(sortedFrpValues[0].toFixed(2)) : null;
const avgFrp = sortedFrpValues.length ? Number((frpSum / sortedFrpValues.length).toFixed(2)) : null;
const p95Frp = percentile(sortedFrpValues, 0.95);
const smallFrpLt50Count = frpValues.filter((value) => value < 50).length;
const extremeFrpGte500Count = frpValues.filter((value) => value >= 500).length;

const detectionUtcValues = detections.map((detection) => detection.detection_utc).filter(Boolean).sort();
const earliestDetectionUtc = detectionUtcValues.length ? detectionUtcValues[0] : null;
const latestDetectionUtc = detectionUtcValues.length ? detectionUtcValues[detectionUtcValues.length - 1] : null;
const latestDay = Object.keys(detectionsByDay).sort().slice(-1)[0] || null;
const latestDayCount = latestDay ? detectionsByDay[latestDay] : 0;

const topDetectionsByFrp = [...detections]
  .filter((detection) => typeof detection.frp === 'number')
  .sort((a, b) => b.frp - a.frp)
  .slice(0, 20)
  .map((detection) => ({
    latitude: detection.latitude,
    longitude: detection.longitude,
    acq_date: detection.acq_date,
    acq_time: detection.acq_time,
    detection_utc: detection.detection_utc,
    frp: detection.frp,
    confidence: detection.confidence || null,
    daynight: detection.daynight || null,
    satellite: detection.satellite || null,
    instrument: detection.instrument || null,
    bright_ti4: detection.bright_ti4 ?? null,
    bright_ti5: detection.bright_ti5 ?? null
  }));

const topDays = Object.entries(detectionsByDay)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([date, count]) => ({ date, count }));

let summaryEn = `NASA FIRMS returned ${totalDetections} fire detections in the Brazil bounding box over the last ${lookbackDays} days.`;
const signals = [`${totalDetections} FIRMS detections in Brazil bbox over ${lookbackDays} days`];

if (totalDetections > 0) {
  summaryEn += ` Max FRP was ${maxFrp ?? 'n/a'} MW, ${extremeFrpGte500Count} detections were at or above 500 MW, and the latest detection timestamp was ${latestDetectionUtc || 'n/a'}.`;
  signals.push(`Max FRP ${maxFrp ?? 'n/a'} MW`);
  signals.push(`${extremeFrpGte500Count} detections at or above 500 MW`);
  if (latestDay) {
    signals.push(`${latestDayCount} detections on latest day ${latestDay}`);
  }
} else {
  summaryEn += ' No active fire detections were returned for the configured area and lookback window.';
  signals.push('No detections returned in current FIRMS query window');
}

return [{
  json: {
    source: 'NASA_FIRMS',
    source_format: 'csv',
    source_url_template: sourceUrlTemplate,
    source_url: sourceUrlTemplate,
    country: 'BR',
    macroarea: 'environment',
    collected_at: now,
    collected_period: _collectedPeriod,
        is_fresh: isFresh,
    sensor,
    bbox,
    lookback_days: lookbackDays,
    records_schema: headers,
    total_detections: totalDetections,
    earliest_detection_utc: earliestDetectionUtc,
    latest_detection_utc: latestDetectionUtc,
    latest_day: latestDay,
    latest_day_count: latestDayCount,
    detections_by_day: detectionsByDay,
    top_days_by_detection_count: topDays,
    confidence_counts: confidenceCounts,
    daynight_counts: daynightCounts,
    satellite_counts: satelliteCounts,
    frp_stats: {
      min_mw: minFrp,
      avg_mw: avgFrp,
      max_mw: maxFrp,
      p95_mw: p95Frp,
      small_lt_50_count: smallFrpLt50Count,
      extreme_gte_500_count: extremeFrpGte500Count
    },
    top_detections_by_frp: topDetectionsByFrp,
    summary_en: summaryEn,
    signals,
    detections,
    _chart_fields: ["detections", "detections_by_day", "top_detections_by_frp"]
  }
}];

const now = new Date().toISOString();
const meta = $('NASA Parse Signals').item.json;

return [{
  json: {
    source: 'NASA_FIRMS',
    country: 'BR',
    macroarea: 'environment',
    cadenza: 'hourly',
    run_date: now,
    status: 'done',
    completed_at: now,
    total_detections: meta.total_detections || null,
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('NASA FIRMS Parse').item.json;

return [{ json: {
  ...base,
  rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
  rule_based_movement_label: base.movement_label || 'mixed',
  fallback_summary_en: base.summary_en || '',
  movement_label: parsed.movement_label || base.movement_label || 'mixed',
  signals: Array.isArray(parsed.signals) && parsed.signals.length ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
  summary_en: parsed.summary_en || base.summary_en || ''
}}];

// Level 1 — Bounding box stati produttori caffè Brasile
// Veloce, zero DB, tagga ogni detection prima di passare all'AI

const COFFEE_STATES = [
  { uf: 'MG', name: 'Minas Gerais',   latMin: -22.93, latMax: -14.23, lonMin: -51.05, lonMax: -39.85 },
  { uf: 'SP', name: 'São Paulo',      latMin: -25.32, latMax: -19.78, lonMin: -53.11, lonMax: -44.16 },
  { uf: 'ES', name: 'Espírito Santo', latMin: -21.31, latMax: -17.88, lonMin: -41.88, lonMax: -39.69 },
  { uf: 'BA', name: 'Bahia',          latMin: -18.36, latMax:  -8.53, lonMin: -46.62, lonMax: -37.34 },
  { uf: 'RO', name: 'Rondônia',       latMin: -13.70, latMax:  -7.96, lonMin: -66.80, lonMax: -59.78 },
  { uf: 'PR', name: 'Paraná',         latMin: -26.73, latMax: -22.52, lonMin: -54.62, lonMax: -48.02 },
];

function findCoffeeState(lat, lon) {
  for (const s of COFFEE_STATES) {
    if (lat >= s.latMin && lat <= s.latMax && lon >= s.lonMin && lon <= s.lonMax) {
      return s;
    }
  }
  return null;
}

const doc = $input.first().json;
const detections = Array.isArray(doc.detections) ? doc.detections : [];

let coffeeCount = 0;
const statesHit = new Set();

const tagged = detections.map(det => {
  const lat = det.latitude;
  const lon = det.longitude;
  const match = (lat != null && lon != null) ? findCoffeeState(lat, lon) : null;
  if (match) {
    coffeeCount++;
    statesHit.add(match.uf);
  }
  return {
    ...det,
    in_coffee_state: match !== null,
    coffee_state_uf: match ? match.uf : null,
    coffee_state_name: match ? match.name : null,
  };
});

const total = detections.length;

return [{
  json: {
    ...doc,
    detections: tagged,
    l1_coffee_detections: coffeeCount,
    l1_coffee_ratio: total > 0 ? Math.round(coffeeCount / total * 1000) / 1000 : 0,
    l1_affected_states: [...statesHit].sort(),
  }
}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '10_NASA_FIRMS',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
